class SORTracker {
public:
    SORTracker() {

    }

    void add(string name, int score) {
        locations.emplace(score, name);
        query_count++;
    }

    string get() {
        auto it = locations.begin();
        advance(it, query_count - 1);
        string result = it->second;
        locations.erase(it);
        return result;
    }
private:
    tree< pair<int, string>, nullptr, greater<pair<int, string>>> locations;
    int query_count = 0;
};
```
